#include <stdio.h>
#include <string.h>
#include <openssl/sha.h>

// Define Ethereum transaction structure
typedef struct {
 unsigned int nonce;
 unsigned long long gasPrice;
 unsigned int gasLimit;
 unsigned char recipient[20];
 unsigned long long value;
} EthereumTransaction;

// Function to create Ethereum transaction
EthereumTransaction createTransaction(unsigned int nonce, unsigned long long gasPrice, unsigned int gasLimit, unsigned char *recipient, unsigned long long value) {
 EthereumTransaction tx;
 tx.nonce = nonce;
 tx.gasPrice = gasPrice;
 tx.gasLimit = gasLimit;
 memcpy(tx.recipient, recipient, 20);
 tx.value = value;
 return tx;
}

int main() {
 // Set up recipient and value
 unsigned char recipient[] = {0x74, 0x2d, 0x35, 0xcc, 0x66, 0x34, 0xc0, 0x53, 0x29, 0x25, 0xa3, 0xb8, 0x44, 0xbc, 0x9e, 0x75, 0x95, 0xf0, 0xbE, 0xb};
 unsigned long long value = 1 * 10**18; // 1 ETH

 // Set up gas limit and gas price
 unsigned int gasLimit = 21000;
 unsigned long long gasPrice = 20 * 10**9; // 20 Gwei

 // Create transaction
 EthereumTransaction tx = createTransaction(0, gasPrice, gasLimit, recipient, value);

 // Print transaction details
 printf("Nonce: %u\n", tx.nonce);
 printf("Gas Price: %llu\n", tx.gasPrice);
 printf("Gas Limit: %u\n", tx.gasLimit);
 printf("Recipient: %s\n", tx.recipient);
 printf("Value: %llu\n", tx.value);

 return 0;
}
